import { createRule } from "../utils/create-rule.js";
import { getStaticMemberExpression } from "../utils/ast-refinement.js";

const MOCK_METHODS = new Set(["mock", "hoisted", "spyOn"]);

export default createRule({
  name: "no-vitest-mocks",
  meta: {
    type: "problem",
    docs: {
