import { Linter } from "eslint";
import * as tsParser from "@typescript-eslint/parser";
import * as fc from "fast-check";
import * as ts from "typescript";
import { describe, expect, it } from "vitest";
import plugin from "../../src/index.js";

const RECOMMENDED_RULE_IDS = Object.keys(plugin.configs.recommended.rules);
const parser: Linter.Parser = tsParser;
const pluginEntry: NonNullable<Linter.Config["plugins"]>[string] = plugin;

function baseConfig(rules: Linter.RulesRecord): Linter.Config {
  return {
    files: ["**/*.ts", "**/*.js"],
    languageOptions: {
      parser,
      parserOptions: { ecmaVersion: 2022, sourceType: "module" },
    },
    plugins: { "agent-code-guard": pluginEntry },
    rules,
  };
}

const linter = new Linter();

function lintAll(code: string, filename: string = "test.ts"): Linter.LintMessage[] {
  return linter.verify(code, baseConfig(plugin.configs.recommended.rules), {
    filename,
  });
}

function lintOne(code: string, ruleId: string, filename: string = "test.ts"): Linter.LintMessage[] {
  return linter.verify(code, baseConfig({ [ruleId]: "error" }), {
    filename,
  });
}

function isSyntacticallyValid(code: string): boolean {
  const sf = ts.createSourceFile(
    "test.ts",
    code,
    ts.ScriptTarget.Latest,
    false,
    ts.ScriptKind.TS,
  );
  const diags = sf.parseDiagnostics;
  return !diags || diags.length === 0;
}

// Safe-grammar generator: syntactically valid TS sources that should not trip
// any recommended rule. Narrow shapes only: literal const decls, typed decls,
// and plain (non-async) function decls.
const identArb = fc
  .stringMatching(/^[a-z][a-zA-Z0-9]{0,7}$/)
  .filter((s) => !RESERVED.has(s));

const RESERVED = new Set([
  "async", "await", "break", "case", "catch", "class", "const", "continue",
  "debugger", "default", "delete", "do", "else", "enum", "export", "extends",
  "false", "finally", "for", "function", "if", "import", "in", "instanceof",
  "let", "new", "null", "of", "return", "super", "switch", "this", "throw",
  "true", "try", "typeof", "var", "void", "while", "with", "yield", "as",
  "then", "query", "mock", "spyOn", "hoisted",
]);

const safeStringArb = fc
  .stringMatching(/^[a-z]{0,12}$/)
  .map((s) => `"${s}"`);
const safeNumberArb = fc.integer({ min: 0, max: 1000 }).map((n) => String(n));
const safeBoolArb = fc.constantFrom("true", "false");

const safeLiteralArb = fc.oneof(safeStringArb, safeNumberArb, safeBoolArb);

const literalDeclArb = fc
  .tuple(identArb, safeLiteralArb)
  .map(([id, lit]) => `const ${id} = ${lit};`);

const typedDeclArb = fc
  .tuple(identArb, fc.constantFrom("number", "string", "boolean"))
  .chain(([id, ty]) => {
    const litArb =
      ty === "number" ? safeNumberArb : ty === "string" ? safeStringArb : safeBoolArb;
    return litArb.map((lit) => `const ${id}: ${ty} = ${lit};`);
  });

const plainFnArb = fc
  .tuple(identArb, identArb, safeNumberArb)
  .map(([fname, pname, n]) =>
    `function ${fname}(${pname}: number): number { return ${pname} + ${n}; }`,
  );

const safeStmtArb = fc.oneof(literalDeclArb, typedDeclArb, plainFnArb);

const safeSourceArb = fc
  .array(safeStmtArb, { minLength: 1, maxLength: 5 })
  .map((stmts) => stmts.join("\n"));

describe("property: rule correctness", () => {
  it("Property 1: no recommended rule fires on safe TS sources", () => {
    fc.assert(
      fc.property(safeSourceArb, (code) => {
        if (!isSyntacticallyValid(code)) return; // skip, not fail
        const messages = lintAll(code);
        if (messages.length !== 0) {
          throw new Error(
            `Safe source produced ${messages.length} report(s):\n` +
              `--- source ---\n${code}\n--- reports ---\n` +
              messages
                .map((m) => `  [${m.ruleId ?? "?"}] ${m.message}`)
                .join("\n"),
          );
        }
      }),
      { numRuns: 200 },
    );
  });

  // Seed anti-pattern per rule (lifted from the first invalid case of each
  // rule's hand-written test). Also records ruleIds that may legitimately
  // co-fire with the seed — empty for all current seeds, but kept as a slot
  // so a reviewer can whitelist a future co-firing without loosening the
  // assertion.
  const SEEDS: ReadonlyArray<{
    ruleId: string;
    seed: string;
    coFire: ReadonlyArray<string>;
    filename?: string;
  }> = [
    { ruleId: "agent-code-guard/async-keyword", seed: "async function foo() {}", coFire: [] },
    {
      ruleId: "agent-code-guard/as-unknown-as",
      seed: "const row = raw as unknown as UserRow;",
      coFire: [],
    },
    {
      ruleId: "agent-code-guard/promise-type",
      seed: "function foo(): Promise<number> { return Promise.resolve(1); }",
      coFire: [],
    },
    {
      ruleId: "agent-code-guard/then-chain",
      seed: "Promise.resolve(1).then((v) => v);",
      coFire: [],
    },
    {
      ruleId: "agent-code-guard/bare-catch",
      seed: "try { doThing(); } catch {}",
      coFire: [],
    },
    {
      ruleId: "agent-code-guard/effect-promise",
      seed: "const run = () => Effect.promise(() => fetch('/x'));",
      coFire: [],
    },
    {
      ruleId: "agent-code-guard/effect-error-erasure",
      seed: "const fail = () => Effect.fail(new Error('boom'));",
      coFire: [],
    },
    {
      ruleId: "agent-code-guard/either-discriminant",
      seed: "if (Either.isLeft(result)) return result.left;",
      coFire: [],
    },
    {
      ruleId: "agent-code-guard/manual-tagged-error",
      seed: "class RunError extends Error { readonly _tag = 'RunError' as const; }",
      coFire: [],
    },
    {
      ruleId: "agent-code-guard/no-unbounded-concurrency",
      seed: "yield* Effect.all(tasks, { concurrency: 'unbounded' });",
      coFire: [],
    },
    {
      ruleId: "agent-code-guard/no-process-env-at-runtime",
      seed: "const port = process.env.PORT;",
      coFire: [],
    },
    {
      ruleId: "agent-code-guard/manual-result",
      seed: "const Result = { ok: (value: number) => ({ ok: true as const, value }), err: (error: Error) => ({ ok: false as const, error }), match: (input: unknown) => input };",
      coFire: [],
    },
    {
      ruleId: "agent-code-guard/manual-option",
      seed: "const Option = { some: (value: number) => ({ _tag: 'Some' as const, value }), none: { _tag: 'None' as const }, flatMap: (apply: (value: number) => unknown) => apply(1) };",
      coFire: [],
    },
    {
      ruleId: "agent-code-guard/manual-brand",
      seed: "const asUserId = (value: string): UserId => value as UserId;",
      coFire: [],
    },
    {
      ruleId: "agent-code-guard/record-cast",
      seed: "const r = {} as Record<string, unknown>;",
      coFire: [],
    },
    {
      ruleId: "agent-code-guard/no-raw-sql",
      seed: "db.query('SELECT * FROM users');",
      coFire: [],
    },
    {
      ruleId: "agent-code-guard/no-manual-enum-cast",
      seed: "const s = x as 'active' | 'inactive';",
      coFire: [],
    },
    {
      ruleId: "agent-code-guard/no-hardcoded-secrets",
      seed: "const apiKey = 'sk_live_abc123xyz0987654321';",
      coFire: [],
    },
    {
      ruleId: "agent-code-guard/no-raw-throw-new-error",
      seed: "throw new Error('boom');",
      coFire: [],
    },
    {
      ruleId: "agent-code-guard/no-test-skip-only",
      seed: "it.skip('wip', () => {});",
      coFire: [],
      filename: "src/auth.test.ts",
    },
    {
      ruleId: "agent-code-guard/no-coverage-threshold-gate",
      seed: "module.exports = { coverageThreshold: { global: { lines: 80 } } };",
      coFire: [],
      filename: "jest.config.js",
    },
    {
      ruleId: "agent-code-guard/no-hardcoded-assertion-literals",
      seed: 'expect(result).toBe("processed");',
      coFire: [],
      filename: "src/foo.test.ts",
    },
    {
      ruleId: "agent-code-guard/tag-discriminant",
      seed: "if (err._tag === 'WebhookTimeoutError') return;",
      coFire: [],
    },
  ];

  const renameArb = fc
    .stringMatching(/^[a-z][a-zA-Z0-9]{0,6}$/)
    .filter((s) => !RESERVED.has(s));

  const paddingArb = fc.constantFrom("", " ", "\n", "  ", "\n\n", "\t");

  // Small, rule-preserving mutations: whitespace padding + identifier rename
  // of a single target ident. Rename is applied as whole-word replace so
  // substrings of keywords are untouched.
  function mutate(seed: string, pad: string, ident: string, rename: string): string {
    const renamed =
      ident.length > 0
        ? seed.replace(new RegExp(`\\b${escapeRegex(ident)}\\b`, "g"), rename)
        : seed;
    return `${pad}${renamed}${pad}`;
  }

  function escapeRegex(s: string): string {
    return s.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
  }

  const IDENTS_BY_SEED: Record<string, string> = {
    "agent-code-guard/async-keyword": "foo",
    "agent-code-guard/as-unknown-as": "raw",
    "agent-code-guard/promise-type": "foo",
    "agent-code-guard/then-chain": "", // no rename target — `.then` is the trigger
    "agent-code-guard/bare-catch": "doThing",
    "agent-code-guard/effect-promise": "run",
    "agent-code-guard/effect-error-erasure": "",
    "agent-code-guard/either-discriminant": "result",
    "agent-code-guard/manual-tagged-error": "RunError",
    "agent-code-guard/no-unbounded-concurrency": "tasks",
    "agent-code-guard/no-process-env-at-runtime": "port",
    "agent-code-guard/manual-result": "input",
    "agent-code-guard/manual-option": "apply",
    "agent-code-guard/manual-brand": "value",
    "agent-code-guard/record-cast": "r",
    "agent-code-guard/no-raw-sql": "db",
    "agent-code-guard/no-manual-enum-cast": "s",
    // Rename exercises the value-shape detector added in acg#10: the seed's
    // LHS is `apiKey`, mutation renames it to a random non-secret-looking
    // ident, and the rule still fires because `sk_live_...` matches the
    // Stripe canonical shape regex.
    "agent-code-guard/no-hardcoded-secrets": "apiKey",
    "agent-code-guard/no-raw-throw-new-error": "",
    "agent-code-guard/no-test-skip-only": "",
    "agent-code-guard/no-coverage-threshold-gate": "",
    // Rename exercises the argument identifier; the string literal "processed" still fires
    "agent-code-guard/no-hardcoded-assertion-literals": "result",
    "agent-code-guard/tag-discriminant": "",
  };

  for (const { ruleId, seed, coFire, filename } of SEEDS) {
    it(`Property 2: ${ruleId} fires on its anti-pattern across mutations`, () => {
      const targetIdent = IDENTS_BY_SEED[ruleId] ?? "";
      fc.assert(
        fc.property(paddingArb, renameArb, (pad, rename) => {
          const code = mutate(seed, pad, targetIdent, rename);
          if (!isSyntacticallyValid(code)) return;
          const allMessages = lintAll(code, filename);
          const firedIds = new Set(
            allMessages
              .map((m) => m.ruleId)
              .filter((id): id is string => id != null),
          );
          const ownFired = firedIds.has(ruleId);
          const unexpected = [...firedIds].filter(
            (id) => id !== ruleId && !coFire.includes(id),
          );
          if (!ownFired || unexpected.length > 0) {
            throw new Error(
              `Mutation broke expectations for ${ruleId}:\n` +
                `--- source ---\n${code}\n` +
                `--- own fired: ${ownFired} ---\n` +
                `--- unexpected: ${unexpected.join(", ") || "(none)"} ---\n` +
                `--- all reports ---\n` +
                allMessages
                  .map((m) => `  [${m.ruleId ?? "?"}] ${m.message}`)
                  .join("\n"),
            );
          }
        }),
        { numRuns: 20 },
      );
    });
  }

  // Property 4: no-hardcoded-assertion-literals does not fire on structural assertions.
  // Structural = identifier or member-expression as the expected arg, never a literal.
  it("Property 4: no-hardcoded-assertion-literals: structural assertions are not flagged", () => {
    const RULE_ID = "agent-code-guard/no-hardcoded-assertion-literals";
    const MATCHER_ARB = fc.constantFrom("toBe", "toEqual", "toStrictEqual", "toContain");
    fc.assert(
      fc.property(identArb, identArb, MATCHER_ARB, (actual, expected, matcher) => {
        const code = `expect(${actual}).${matcher}(${expected});`;
        if (!isSyntacticallyValid(code)) return;
        const messages = lintOne(code, RULE_ID, "src/foo.test.ts");
        if (messages.length !== 0) {
          throw new Error(
            `Structural assertion falsely flagged:\n--- source ---\n${code}\n` +
              messages.map((m) => `  [${m.ruleId ?? "?"}] ${m.message}`).join("\n"),
          );
        }
      }),
      { numRuns: 100 },
    );
  });

  it("Property 5: no-hardcoded-assertion-literals fires on hardcoded literals across supported assertion APIs", () => {
    const RULE_ID = "agent-code-guard/no-hardcoded-assertion-literals";
    const matcherArb = fc.constantFrom("toBe", "toEqual", "toStrictEqual", "toContain", "toMatch");
    const memberAssertArb = fc.constantFrom("equal", "strictEqual", "deepEqual");
    const stringLiteralArb = fc.stringMatching(/^[a-z]{4,12}$/).map((s) => JSON.stringify(s));
    const negativeNumberArb = fc.integer({ min: 3, max: 200 }).map((n) => `-${n}`);

    fc.assert(
      fc.property(
        identArb,
        identArb,
        matcherArb,
        stringLiteralArb,
        (actual, expected, matcher, literal) => {
          const code = `expect(${actual}).${matcher}(${literal});`;
          const messages = lintOne(code, RULE_ID, "src/foo.test.ts");
          if (messages.length === 0) {
            throw new Error(`Literal matcher was not flagged:\n${code}`);
          }
        },
      ),
      { numRuns: 40 },
    );

    fc.assert(
      fc.property(
        identArb,
        identArb,
        memberAssertArb,
        stringLiteralArb,
        (actual, expected, matcher, literal) => {
          const code = `assert.${matcher}(${actual}, ${literal});`;
          const messages = lintOne(code, RULE_ID, "src/foo.test.ts");
          if (messages.length === 0) {
            throw new Error(`assert.${matcher} literal was not flagged:\n${code}`);
          }
        },
      ),
      { numRuns: 30 },
    );

    fc.assert(
      fc.property(identArb, negativeNumberArb, (actual, literal) => {
        const code = `expect(${actual}).toBe(${literal});`;
        const messages = lintOne(code, RULE_ID, "src/foo.test.ts");
        if (messages.length === 0) {
          throw new Error(`Negative magic number was not flagged:\n${code}`);
        }
      }),
      { numRuns: 20 },
    );
  });

  it("Property 6: no-process-env-at-runtime ignores shadowed process bindings", () => {
    const RULE_ID = "agent-code-guard/no-process-env-at-runtime";
    fc.assert(
      fc.property(identArb, safeStringArb, (key, value) => {
        const code =
          `const process = { env: { ${key}: ${value} } };\n` +
          `const current = process.env.${key};`;
        if (!isSyntacticallyValid(code)) return;
        const messages = lintOne(code, RULE_ID);
        if (messages.length !== 0) {
          throw new Error(
            `Shadowed process binding falsely flagged:\n--- source ---\n${code}\n` +
              messages.map((m) => `  [${m.ruleId ?? "?"}] ${m.message}`).join("\n"),
          );
        }
      }),
      { numRuns: 100 },
    );
  });

  it("Property 7: no-unbounded-concurrency ignores bounded Effect fan-out", () => {
    const RULE_ID = "agent-code-guard/no-unbounded-concurrency";
    const methodArb = fc.constantFrom("all", "forEach", "validateAll");

    fc.assert(
      fc.property(methodArb, fc.integer({ min: 1, max: 64 }), (method, concurrency) => {
        const code =
          method === "forEach"
            ? `yield* Effect.${method}(tasks, runTask, { concurrency: ${concurrency} });`
            : `yield* Effect.${method}(tasks, { concurrency: ${concurrency} });`;
        if (!isSyntacticallyValid(code)) return;
        const messages = lintOne(code, RULE_ID);
        if (messages.length !== 0) {
          throw new Error(
            `Bounded concurrency falsely flagged:\n--- source ---\n${code}\n` +
              messages.map((m) => `  [${m.ruleId ?? "?"}] ${m.message}`).join("\n"),
          );
        }
      }),
      { numRuns: 100 },
    );
  });

  it("Property 8: no-hardcoded-secrets keeps name-gated detection across declaration shapes", () => {
    const RULE_ID = "agent-code-guard/no-hardcoded-secrets";
    const exactTwentyArb = fc.stringMatching(/^[A-Za-z0-9]{20}$/);
    const placeholderArb = fc.constantFrom(
      '"your-api-key-goes-here"',
      '"your-token-goes-here-now"',
    );
    const spacedArb = fc.constantFrom(
      '"not a secret because it has spaces"',
      '"safe words with spaces stay safe"',
    );

    fc.assert(
      fc.property(exactTwentyArb, (secretish) => {
        const snippets = [
          `const apiKey = "${secretish}";`,
          `const config = { "apiKey": "${secretish}" };`,
          `apiKey = "${secretish}";`,
          `client.apiKey = "${secretish}";`,
        ];
        for (const code of snippets) {
          const messages = lintOne(code, RULE_ID);
          if (messages.length === 0) {
            throw new Error(`Name-gated secret was not flagged:\n${code}`);
          }
        }
      }),
      { numRuns: 40 },
    );

    fc.assert(
      fc.property(fc.oneof(placeholderArb, spacedArb), (literal) => {
        const snippets = [
          `const token = ${literal};`,
          `const config = { "apiKey": ${literal} };`,
          `client["apiKey"] = ${literal};`,
        ];
        for (const code of snippets) {
          const messages = lintOne(code, RULE_ID);
          if (messages.length !== 0) {
            throw new Error(`Safe secret-shaped placeholder was flagged:\n${code}`);
          }
        }
      }),
      { numRuns: 20 },
    );
  });

  // Property 3: fixer idempotence. Scoped to rules that declare `fixable`.
  // No recommended rule currently declares one — this is a guard that will
  // light up once a fixer lands.
  const FIXABLE_RULE_IDS = Object.entries(plugin.rules)
    .filter(([, r]) => r.meta.fixable)
    .map(([name]) => `agent-code-guard/${name}`);

  it("Property 3: fixer idempotence (skipped if no fixable rules)", () => {
    if (FIXABLE_RULE_IDS.length === 0) {
      expect(FIXABLE_RULE_IDS).toHaveLength(0);
      return;
    }
    for (const ruleId of FIXABLE_RULE_IDS) {
      const entry = SEEDS.find((s) => s.ruleId === ruleId);
      if (entry === undefined) continue;
      const filename = entry.filename ?? "test.ts";
      const { output } = linter.verifyAndFix(
        entry.seed,
        baseConfig({ [ruleId]: "error" }),
        { filename },
      );
      const after = lintOne(output, ruleId, filename);
      expect(after, `Fixer for ${ruleId} not idempotent: ${after.length} report(s) remain`).toHaveLength(0);
    }
  });
});

tests/property/ast-refinement.test.ts.source:
import * as tsParser from "@typescript-eslint/parser";
import * as fc from "fast-check";
import { AST_NODE_TYPES } from "@typescript-eslint/utils";
import type { TSESTree } from "@typescript-eslint/utils";
import { describe, expect, it } from "vitest";
import {
  getEnclosingFunctionName,
  getFirst,
  getNumericLiteralValue,
  getParent,
  getStaticMemberPropertyName,
  getStaticStringKey,
  getStringLiteralValue,
  getTagAccess,
  isFunctionReturnTypeReference,
} from "../../src/utils/ast-refinement.js";

const RESERVED = new Set([
  "async", "await", "break", "case", "catch", "class", "const", "continue",
  "debugger", "default", "delete", "do", "else", "enum", "export", "extends",
  "false", "finally", "for", "function", "if", "import", "in", "instanceof",
  "let", "new", "null", "of", "return", "super", "switch", "this", "throw",
  "true", "try", "typeof", "var", "void", "while", "with", "yield",
]);

const identArb = fc
  .stringMatching(/^[a-z][a-zA-Z0-9]{0,7}$/)
  .filter((name) => !RESERVED.has(name));

const safeStringArb = fc.stringMatching(/^[a-z]{0,12}$/);
const nonNegativeIntArb = fc.integer({ min: 0, max: 1000 });
const positiveIntArb = fc.integer({ min: 1, max: 1000 });

function parseWithParents(code: string): TSESTree.Program {
  const program = tsParser.parse(code, {
    ecmaVersion: 2022,
    sourceType: "module",
    range: true,
  }) as TSESTree.Program;
  attachParents(program, undefined);
  return program;
}

function attachParents(node: unknown, parent: TSESTree.Node | undefined): void {
  if (!isNode(node)) return;
  if (parent) {
    (node as TSESTree.Node & { parent?: TSESTree.Node }).parent = parent;
  }
  for (const [key, value] of Object.entries(node)) {
    if (key === "parent") continue;
    if (Array.isArray(value)) {
      for (const child of value) {
        attachParents(child, node);
      }
      continue;
    }
    attachParents(value, node);
  }
}

function isNode(value: unknown): value is TSESTree.Node {
  return (
    typeof value === "object" &&
    value !== null &&
    "type" in value &&
    typeof (value as { type: unknown }).type === "string"
  );
}

function firstObjectProperty(code: string): TSESTree.Property {
  const program = parseWithParents(code);
  const statement = program.body[0];
  if (
    statement?.type !== AST_NODE_TYPES.VariableDeclaration ||
    statement.declarations[0]?.init?.type !== AST_NODE_TYPES.ObjectExpression
  ) {
    throw new Error(`expected object literal snippet:\n${code}`);
  }
  const property = statement.declarations[0].init.properties[0];
  if (!property || property.type !== AST_NODE_TYPES.Property) {
    throw new Error(`expected first property in:\n${code}`);
  }
  return property;
}

function firstInitializer(code: string): TSESTree.Expression {
  const program = parseWithParents(code);
  const statement = program.body[0];
  const init =
    statement?.type === AST_NODE_TYPES.VariableDeclaration
      ? statement.declarations[0]?.init
      : null;
  if (!init || init.type === AST_NODE_TYPES.SpreadElement) {
    throw new Error(`expected expression initializer in:\n${code}`);
  }
  return init;
}

function firstExpression(code: string): TSESTree.Expression {
  const program = parseWithParents(code);
  const statement = program.body[0];
  if (statement?.type !== AST_NODE_TYPES.ExpressionStatement) {
    throw new Error(`expected expression statement in:\n${code}`);
  }
  return statement.expression;
}

function allNodes<T extends TSESTree.Node>(
  node: TSESTree.Node,
  predicate: (candidate: TSESTree.Node) => candidate is T,
): T[] {
  const results: T[] = [];
  visit(node, (candidate) => {
    if (predicate(candidate)) results.push(candidate);
  });
  return results;
}

function visit(node: TSESTree.Node, fn: (node: TSESTree.Node) => void): void {
  fn(node);
  for (const [key, value] of Object.entries(node)) {
    if (key === "parent") continue;
    if (Array.isArray(value)) {
      for (const child of value) {
        if (isNode(child)) visit(child, fn);
      }
      continue;
    }
    if (isNode(value)) visit(value, fn);
  }
}

describe("property: ast refinement", () => {
  it("Property 1: getFirst matches JS head semantics", () => {
    fc.assert(
      fc.property(fc.array(fc.integer(), { maxLength: 5 }), (values) => {
        expect(getFirst(values)).toBe(values[0] ?? null);
      }),
      { numRuns: 100 },
    );
  });

  it("Property 1a: getFirst collapses explicit undefined to null", () => {
    expect(getFirst([undefined])).toBeNull();
  });

  it("Property 2: getStaticStringKey accepts static object keys and rejects dynamic ones", () => {
    fc.assert(
      fc.property(identArb, safeStringArb, (ident, text) => {
        const identProp = firstObjectProperty(`const obj = { ${ident}: 1 };`);
        expect(getStaticStringKey(identProp.key, identProp.computed)).toBe(ident);

        const quotedProp = firstObjectProperty(
          `const obj = { ${JSON.stringify(text)}: 1 };`,
        );
        expect(getStaticStringKey(quotedProp.key, quotedProp.computed)).toBe(text);

        const templateProp = firstObjectProperty(`const obj = { [\`${text}\`]: 1 };`);
        expect(getStaticStringKey(templateProp.key, templateProp.computed)).toBe(text);

        const dynamicProp = firstObjectProperty(`const obj = { [${ident}]: 1 };`);
        expect(getStaticStringKey(dynamicProp.key, dynamicProp.computed)).toBeNull();

        const interpolatedTemplateProp = firstObjectProperty(
          "const obj = { [`" + text + "${" + ident + "}`]: 1 };",
        );
        expect(
          getStaticStringKey(
            interpolatedTemplateProp.key,
            interpolatedTemplateProp.computed,
          ),
        ).toBeNull();
      }),
      { numRuns: 80 },
    );
  });

  it("Property 3: literal helpers preserve string and numeric shapes", () => {
    fc.assert(
      fc.property(safeStringArb, nonNegativeIntArb, positiveIntArb, (text, n, positive) => {
        expect(getStringLiteralValue(firstInitializer(`const value = ${JSON.stringify(text)};`))).toBe(text);
        expect(getStringLiteralValue(firstInitializer(`const value = \`${text}\`;`))).toBe(text);
        expect(getStringLiteralValue(firstInitializer(`const value = \`${text}\${suffix}\`;`))).toBeNull();

        expect(getNumericLiteralValue(firstInitializer(`const value = ${n};`))).toBe(n);
        expect(getNumericLiteralValue(firstInitializer(`const value = -${positive};`))).toBe(-positive);
        expect(getNumericLiteralValue(firstInitializer(`const value = +${positive};`))).toBeNull();
      }),
      { numRuns: 80 },
    );
  });

  it("Property 4: member-name helpers normalize plain and optional `_tag` access only", () => {
    fc.assert(
      fc.property(identArb, (target) => {
        const direct = firstExpression(`${target}._tag;`);
        expect(getStaticMemberPropertyName(direct)).toBe("_tag");
        expect(getTagAccess(direct)).not.toBeNull();

        const optional = firstExpression(`${target}?._tag;`);
        expect(getStaticMemberPropertyName(optional)).toBe("_tag");
        expect(getTagAccess(optional)).not.toBeNull();

        const computed = firstExpression(`${target}["_tag"];`);
        expect(getStaticMemberPropertyName(computed)).toBeNull();
        expect(getTagAccess(computed)).toBeNull();

        const other = firstExpression(`${target}.status;`);
        expect(getStaticMemberPropertyName(other)).toBe("status");
        expect(getTagAccess(other)).toBeNull();
      }),
      { numRuns: 60 },
    );
  });

  it("Property 5: getEnclosingFunctionName recovers names from supported function containers", () => {
    fc.assert(
      fc.property(identArb, identArb, identArb, identArb, identArb, (fnName, localName, propName, quotedName, methodName) => {
        const program = parseWithParents(`
          function ${fnName}() { throw new Error("x"); }
          const ${localName} = () => { throw new Error("x"); };
          const obj = {
            ${propName}() { throw new Error("x"); },
            ${JSON.stringify(quotedName)}: () => { throw new Error("x"); },
          };
          class Box {
            ${methodName}() { throw new Error("x"); }
          }
          Promise.resolve().then(() => { throw new Error("x"); });
        `);

        const throws = allNodes(
          program,
          (node): node is TSESTree.ThrowStatement => node.type === AST_NODE_TYPES.ThrowStatement,
        );
        const names = throws.map((node) => getEnclosingFunctionName(node));
        expect(names).toEqual([
          fnName,
          localName,
          propName,
          quotedName,
          methodName,
          null,
        ]);
      }),
      { numRuns: 30 },
    );
  });

  it("Property 6: Promise return-type detection only fires for function return positions", () => {
    fc.assert(
      fc.property(identArb, identArb, identArb, (fnName, methodName, aliasName) => {
        const program = parseWithParents(`
          function ${fnName}(): Promise<number> { return Promise.resolve(1); }
          interface Box { ${methodName}(): Promise<number>; }
          type ${aliasName} = Promise<number>;
        `);
        const refs = allNodes(
          program,
          (node): node is TSESTree.TSTypeReference =>
            node.type === AST_NODE_TYPES.TSTypeReference &&
            node.typeName.type === AST_NODE_TYPES.Identifier &&
            node.typeName.name === "Promise",
        );
        expect(refs.map((node) => isFunctionReturnTypeReference(node))).toEqual([
          true,
          true,
          false,
        ]);
      }),
      { numRuns: 40 },
    );
  });

  it("Property 7: malformed empty template literals stay safely null", () => {
    const emptyTemplate = {
      type: AST_NODE_TYPES.TemplateLiteral,
      expressions: [],
      quasis: [],
    } as TSESTree.TemplateLiteral;

    expect(getStaticStringKey(emptyTemplate, true)).toBeNull();
    expect(getStringLiteralValue(emptyTemplate)).toBeNull();
  });

  it("Property 8: parent helpers return null at the top level and for computed owners", () => {
    const program = parseWithParents(`
      const obj = {
        [name]: () => { throw new Error("x"); },
      };
    `);
    const declaration = program.body[0];
    if (
      declaration?.type !== AST_NODE_TYPES.VariableDeclaration ||
      declaration.declarations[0]?.init?.type !== AST_NODE_TYPES.ObjectExpression
    ) {
      throw new Error("expected object literal");
    }

    const property = declaration.declarations[0].init.properties[0];
    if (property?.type !== AST_NODE_TYPES.Property) {
      throw new Error("expected property");
    }

    const throws = allNodes(
      program,
      (node): node is TSESTree.ThrowStatement => node.type === AST_NODE_TYPES.ThrowStatement,
    );

    expect(getParent(program)).toBeNull();
    expect(getEnclosingFunctionName(throws[0]!)).toBeNull();
  });

  it("getEnclosingFunctionName returns null for unsupported function containers", () => {
    const program = parseWithParents(`
      const handlers = [() => { throw new Error("x"); }];
      let assigned;
      assigned = () => { throw new Error("y"); };
      function outer() {
        const nested = [() => { throw new Error("z"); }];
        return nested;
      }
    `);

    const throws = allNodes(
      program,
      (node): node is TSESTree.ThrowStatement =>
        node.type === AST_NODE_TYPES.ThrowStatement,
    );

    expect(throws.map((node) => getEnclosingFunctionName(node))).toEqual([
      null,
      null,
      null,
    ]);
  });

  it("member helpers reject non-member nodes and computed optional access", () => {
    expect(getStaticMemberPropertyName(firstExpression("run();"))).toBeNull();
    expect(getTagAccess(firstExpression('value?.["_tag"];'))).toBeNull();
  });

  it("isFunctionReturnTypeReference ignores non-return Promise annotations", () => {
    const program = parseWithParents(`
      function run(input: Promise<number>): void { return; }
      const value: Promise<number> = Promise.resolve(1);
      type Box = { value: Promise<number> };
      type Loader = () => Promise<number>;
    `);

    const refs = allNodes(
      program,
      (node): node is TSESTree.TSTypeReference =>
        node.type === AST_NODE_TYPES.TSTypeReference &&
        node.typeName.type === AST_NODE_TYPES.Identifier &&
        node.typeName.name === "Promise",
    );

    expect(refs.map((node) => isFunctionReturnTypeReference(node))).toEqual([
      false,
      false,
      false,
      true,
    ]);
  });
});

tests/manual-tagged-error.test.ts.source:
import { RuleTester } from "@typescript-eslint/rule-tester";
import { afterAll, describe, it } from "vitest";
import rule from "../src/rules/manual-tagged-error.js";

RuleTester.afterAll = afterAll;
RuleTester.it = it;
