import { RuleTester } from "@typescript-eslint/rule-tester";
import { afterAll, describe, it } from "vitest";
import rule from "../src/rules/no-hardcoded-assertion-literals.js";

RuleTester.afterAll = afterAll;
RuleTester.it = it;
RuleTester.itOnly = it.only;
RuleTester.describe = describe;

const ruleTester = new RuleTester({
  languageOptions: {
    parser: require("@typescript-eslint/parser"),
    parserOptions: { ecmaVersion: 2022, sourceType: "module" },
  },
});

ruleTester.run("no-hardcoded-assertion-literals", rule, {
  valid: [
    { filename: "/repo/src/auth.test.ts", code: "expect(x).toBe('ok');" },
    { filename: "/repo/src/auth.test.ts", code: "expect(arr.length).toBe(0);" },
    { filename: "/repo/src/auth.test.ts", code: "expect(count).toBe(1);" },
    { filename: "/repo/src/auth.test.ts", code: "expect(result).toBe(-1);" },
    { filename: "/repo/src/auth.test.ts", code: "expect(arr.length).toBe(2);" },
    { filename: "/repo/src/auth.test.ts", code: "expect(result).toBe();" },
    { filename: "/repo/src/auth.test.ts", code: "expect(result).toBe(+42);" },
    {
      filename: "/repo/src/auth.test.ts",
      code: "const EXPECTED = 'processed'; expect(x).toBe(EXPECTED);",
    },
    { filename: "/repo/src/auth.test.ts", code: "expect(x).toBe(Status.Active);" },
    { filename: "/repo/src/auth.test.ts", code: "expect(result).toHaveProperty('processed');" },
    { filename: "/repo/src/auth.test.ts", code: "expect(result)['toBe']('processed');" },
    // Non-test file — rule is silent outside test files
    { filename: "/repo/src/auth.ts", code: "expect(x).toBe('hardcoded-value');" },
    { filename: "/repo/src/auth.test.ts", code: "expect(x).toBe(`prefix-${id}`);" },
    {
      filename: "/repo/src/auth.test.ts",
      code: "expect(x).toBe('process');",
      options: [{ allowShorterThan: 10 }],
    },
    { filename: "/repo/tests/auth.ts", code: "assert.equal(result, EXPECTED_STATUS);" },
    { filename: "/repo/tests/auth.ts", code: "helper.equal(result, 'processed');" },
    { filename: "/repo/tests/auth.ts", code: "assert.ok(result, 'processed');" },
    { filename: "/repo/src/auth.test.ts", code: "assert.equal(result);" },
    {
      filename: "/repo/src/auth.test.ts",
      code: "class T { #toBe(value: string) {} run(result: string) { this.#toBe('processed'); } }",
    },
    {
      filename: "/repo/src/auth.test.ts",
      code: "class AssertBox { #equal(actual: string, expected: string) { return [actual, expected]; } run(assert: AssertBox, result: string) { return assert.#equal(result, 'processed'); } }",
    },
    // .toHaveLength is not in the detected matcher set
    { filename: "/repo/src/auth.test.ts", code: "expect(arr).toHaveLength(10);" },
    // Regex arg to toMatch is not a string literal
    { filename: "/repo/src/auth.test.ts", code: "expect(msg).toMatch(/error/);" },
    { filename: "/repo/src/auth.test.ts", code: "assertEquals(result, EXPECTED);" },
    { filename: "/repo/src/auth.test.ts", code: "checkEquals(result, 'processed');" },
    { filename: "/repo/src/auth.test.ts", code: "assertEquals(result);" },
  ],
  invalid: [
    // vitest/.toBe with string literal (length ≥ 4)
    {
      filename: "/repo/src/auth.test.ts",
      code: "expect(result).toBe('processed');",
      errors: [{ messageId: "hardcodedLiteral" }],
    },
    // vitest/.toEqual with string literal
    {
      filename: "/repo/src/auth.test.ts",
      code: "expect(result).toEqual('active');",
      errors: [{ messageId: "hardcodedLiteral" }],
    },
    // vitest/.toStrictEqual with string literal
    {
      filename: "/repo/src/auth.test.ts",
      code: "expect(result).toStrictEqual('pending');",
      errors: [{ messageId: "hardcodedLiteral" }],
    },
    // vitest/.toContain with string literal
    {
      filename: "/repo/src/auth.test.ts",
      code: "expect(items).toContain('admin');",
      errors: [{ messageId: "hardcodedLiteral" }],
    },
    // vitest/.toMatch with string literal
    {
      filename: "/repo/src/auth.test.ts",
      code: "expect(msg).toMatch('error occurred');",
      errors: [{ messageId: "hardcodedLiteral" }],
    },
    // Magic number (non-boundary)
    {
      filename: "/repo/src/auth.test.ts",
      code: "expect(count).toBe(42);",
      errors: [{ messageId: "hardcodedLiteral" }],
    },
    {
      filename: "/repo/src/auth.test.ts",
      code: "expect(count).toBe(-42);",
      errors: [{ messageId: "hardcodedLiteral" }],
    },
    {
      filename: "/repo/src/auth.test.ts",
      code: "expect(count).toBe(-2);",
      errors: [{ messageId: "hardcodedLiteral" }],
    },
    {
      filename: "/repo/src/auth.test.ts",
      code: "expect(result).toBe('four');",
      errors: [{ messageId: "hardcodedLiteral" }],
    },
    // chai/assert.equal — 2nd arg is the expected string
    {
      filename: "/repo/tests/auth.ts",
      code: "assert.equal(result, 'success');",
      errors: [{ messageId: "hardcodedLiteral" }],
    },
    // chai/assert.strictEqual — 2nd arg is a magic number
    {
      filename: "/repo/src/auth.test.ts",
      code: "assert.strictEqual(count, 100);",
      errors: [{ messageId: "hardcodedLiteral" }],
    },
    // assertEquals (Deno/custom) — 2nd arg
    {
      filename: "/repo/src/auth.test.ts",
      code: "assertEquals(result, 'completed');",
      errors: [{ messageId: "hardcodedLiteral" }],
    },
    // Template literal without substitutions (treated as string literal)
    {
      filename: "/repo/src/auth.test.ts",
      code: "expect(result).toBe(`processed`);",
      errors: [{ messageId: "hardcodedLiteral" }],
    },
    // .spec.ts file is also a test file
    {
      filename: "/repo/src/auth.spec.ts",
      code: "expect(x).toBe('verified');",
      errors: [{ messageId: "hardcodedLiteral" }],
    },
    // tests/ directory
    {
      filename: "/repo/tests/auth.ts",
      code: "expect(x).toBe('verified');",
      errors: [{ messageId: "hardcodedLiteral" }],
    },
    // assert.deepEqual — 2nd arg
    {
      filename: "/repo/src/auth.test.ts",
      code: "assert.deepEqual(result, 'active-user');",
      errors: [{ messageId: "hardcodedLiteral" }],
    },
    // __tests__ directory
    {
      filename: "/repo/src/__tests__/auth.ts",
      code: "expect(x).toEqual('active');",
      errors: [{ messageId: "hardcodedLiteral" }],
    },
  ],
});

tests/property/manual-algebra-family.tes.source:
import { Linter } from "eslint";
import * as tsParser from "@typescript-eslint/parser";
import * as fc from "fast-check";
import { describe, expect, it } from "vitest";
import plugin from "../../src/index.js";

const parser: Linter.Parser = tsParser;
const pluginEntry: NonNullable<Linter.Config["plugins"]>[string] = plugin;

function configFor(ruleId: string): Linter.Config {
  return {
    files: ["**/*.ts"],
    languageOptions: {
      parser,
      parserOptions: { ecmaVersion: 2022, sourceType: "module" },
    },
    plugins: {
      "agent-code-guard": pluginEntry,
    },
    rules: { [ruleId]: "error" },
  };
}

const linter = new Linter();
const identArb = fc.stringMatching(/^[A-Z][a-zA-Z]{2,8}$/);
const transportSuffixArb = fc.constantFrom("Response", "Payload", "State", "Config");
const paddingArb = fc.constantFrom("", " ", "\n", "  ", "\n\n", "\t");
const renameArb = fc.stringMatching(/^[a-z][a-zA-Z0-9]{1,8}$/);

function lintOne(
  code: string,
  ruleId: string,
  filename: string = "src/test.ts",
): Linter.LintMessage[] {
  return linter.verify(code, configFor(ruleId), { filename });
}

function mutate(seed: string, pad: string, ident: string, rename: string): string {
  const renamed =
    ident.length > 0
      ? seed.replace(new RegExp(`\\b${escapeRegex(ident)}\\b`, "g"), rename)
      : seed;
  return `${pad}${renamed}${pad}`;
}

function escapeRegex(value: string): string {
  return value.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

describe("property: manual algebra family", () => {
  it("Property 1: manual-result keeps transport/data variants clean", () => {
    fc.assert(
      fc.property(identArb, transportSuffixArb, (name, suffix) => {
        const code = `type ${name}${suffix} = { readonly ok: true; readonly value: string } | { readonly ok: false; readonly error: string };`;
        expect(lintOne(code, "agent-code-guard/manual-result")).toHaveLength(0);
      }),
      { numRuns: 60 },
    );
  });

  it("Property 2: manual-option keeps non-algebraic state wrappers clean", () => {
    fc.assert(
      fc.property(identArb, (name) => {
        const code = `type ${name}State<T> = { readonly _tag: "Some"; readonly value: T } | { readonly _tag: "None" };`;
        expect(lintOne(code, "agent-code-guard/manual-option")).toHaveLength(0);
      }),
      { numRuns: 60 },
    );
  });

  it("Property 3: manual-brand keeps payload/schema variants clean", () => {
    fc.assert(
      fc.property(identArb, (name) => {
        const payload = `type ${name}Payload = { readonly brand: string; readonly id: string };`;
        const schema = `const ${name}Schema = Schema.String.pipe(Schema.brand("${name}"));`;
        expect(lintOne(payload, "agent-code-guard/manual-brand")).toHaveLength(0);
        expect(lintOne(schema, "agent-code-guard/manual-brand")).toHaveLength(0);
      }),
      { numRuns: 60 },
    );
  });

  it("Property 4: manual-result still fires under rename and whitespace mutation", () => {
    const seed = `
      const Result = {
        ok: (value: number) => ({ ok: true as const, value }),
        err: (error: Error) => ({ ok: false as const, error }),
        match: (input: unknown) => input,
      };
    `;
    fc.assert(
      fc.property(paddingArb, renameArb, (pad, rename) => {
        const code = mutate(seed, pad, "input", rename);
        expect(lintOne(code, "agent-code-guard/manual-result")).toHaveLength(1);
      }),
      { numRuns: 30 },
    );
  });

  it("Property 5: manual-option still fires under rename and whitespace mutation", () => {
    const seed = `
      const Option = {
        some: (value: number) => ({ _tag: "Some" as const, value }),
        none: { _tag: "None" as const },
        flatMap: (apply: (value: number) => unknown) => apply(1),
      };
    `;
    fc.assert(
      fc.property(paddingArb, renameArb, (pad, rename) => {
        const code = mutate(seed, pad, "apply", rename);
        expect(lintOne(code, "agent-code-guard/manual-option")).toHaveLength(1);
      }),
      { numRuns: 30 },
    );
  });

  it("Property 6: manual-brand still fires under rename and whitespace mutation", () => {
    const seed = 'const asUserId = (value: string): UserId => value as UserId;';
    fc.assert(
      fc.property(paddingArb, renameArb, (pad, rename) => {
        const code = mutate(seed, pad, "value", rename);
        expect(lintOne(code, "agent-code-guard/manual-brand")).toHaveLength(1);
      }),
      { numRuns: 30 },
    );
  });

  it("Property 7: manual-result still fires on helper functions under rename and whitespace mutation", () => {
    const seed = "function ok(value: number) { return { ok: true as const, value }; }";
    fc.assert(
      fc.property(paddingArb, renameArb, (pad, rename) => {
        const code = mutate(seed, pad, "value", rename);
        expect(lintOne(code, "agent-code-guard/manual-result")).toHaveLength(1);
      }),
      { numRuns: 30 },
    );
  });

  it("Property 8: manual-option still fires on helper functions under rename and whitespace mutation", () => {
    const seed = 'const some = (value: number) => ({ _tag: "Some" as const, value });';
    fc.assert(
      fc.property(paddingArb, renameArb, (pad, rename) => {
        const code = mutate(seed, pad, "value", rename);
        expect(lintOne(code, "agent-code-guard/manual-option")).toHaveLength(1);
      }),
      { numRuns: 30 },
    );
  });
});

